};`;

const AVAILABLE_GLOBALS = `Available globals at runtime (use EXACTLY these names — no variations):
- React
- useCurrentFrame (NOT useCurrentFrames, NOT useFrame)
- useVideoConfig
- interpolate(value, inputRange, outputRange, options?)
